// src/App.js
import React, { useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Calendar from './components/Calendar'; 
import Atendimento from './components/gestao/atendimento';
import Pessoa from './components/gestao/pessoa';
import Workflow from './components/gestao/workflow';
import Timesheet from './components/gestao/timesheet';
import RelatoriosGestao from './components/gestao/relatorios'; 
import ListaAtividades from './components/atividades/lista_atividades'; 
import PainelTarefas from './components/atividades/painel_tarefas';
import KanbanTarefas from './components/atividades/kanban_tarefas';
import RelatoriosAtividades from './components/atividades/relatorios';
import Processos from './components/processos/processos'; 
import Intimacoes from './components/processos/intimacoes';
import CentralCaptura from './components/processos/central_captura_processos'; 
import AndamentosProcessuais from './components/processos/andamentos_processuais';
import RelatoriosProcessos from './components/processos/relatorios';
import ReceitasDespesas from './components/financeiro/receitas_despesas'; 
import ExtratoConta from './components/financeiro/extrato_conta';
import Solicitacoes from './components/financeiro/solicitacoes';
import IntegracaoReceitas from './components/financeiro/integracao_receitas';
import IntegracaoDespesas from './components/financeiro/integracao_despesas'; 
import RelatoriosFinanceiro from './components/financeiro/relatorios';
import Documentos from './components/documentos/documentos'; 
import ModelosDocumentos from './components/documentos/modelos_documentos';
import Conexoes from './components/extensoes/conexoes'; 
import RelatoriosExtensoes from './components/extensoes/relatorios';
import { AuthContext } from './context/AuthContext'; // Importando o contexto de autenticação
import './App.css';

const App = () => {
  const { user } = useContext(AuthContext); // Acessando o contexto de autenticação

  const PrivateRoute = ({ element, permissions }) => {
    return permissions.includes(user.permission) ? element : <Navigate to="/" />;
  };

  return (
    <Router>
      <div className="app-container">
        <Navbar />
        <Header />
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/gestao/atendimento" element={<PrivateRoute element={<Atendimento />} permissions={['admin', 'gestor']} />} />
          <Route path="/gestao/pessoa" element={<PrivateRoute element={<Pessoa />} permissions={['admin', 'gestor']} />} />
          <Route path="/gestao/workflow" element={<PrivateRoute element={<Workflow />} permissions={['admin', 'gestor']} />} />
          <Route path="/gestao/timesheet" element={<PrivateRoute element={<Timesheet />} permissions={['admin', 'gestor']} />} />
          <Route path="/gestao/relatorios" element={<PrivateRoute element={<RelatoriosGestao />} permissions={['admin', 'gestor']} />} />
          <Route path="/atividades" element={<PrivateRoute element={<ListaAtividades />} permissions={['admin', 'gestor', 'colaborador']} />} />
          <Route path="/atividades/painel" element={<PrivateRoute element={<PainelTarefas />} permissions={['admin', 'gestor', 'colaborador']} />} />
          <Route path="/atividades/kanban" element={<PrivateRoute element={<KanbanTarefas />} permissions={['admin', 'gestor', 'colaborador']} />} />
          <Route path="/atividades/relatorios" element={<PrivateRoute element={<RelatoriosAtividades />} permissions={['admin', 'gestor']} />} />
          <Route path="/processos" element={<PrivateRoute element={<Processos />} permissions={['admin', 'gestor']} />} />
          <Route path="/processos/intimacoes" element={<PrivateRoute element={<Intimacoes />} permissions={['admin', 'gestor']} />} />
          <Route path="/processos/central-captura" element={<PrivateRoute element={<CentralCaptura />} permissions={['admin', 'gestor']} />} />
          <Route path="/processos/andamentos" element={<PrivateRoute element={<AndamentosProcessuais />} permissions={['admin', 'gestor']} />} />
          <Route path="/processos/relatorios" element={<PrivateRoute element={<RelatoriosProcessos />} permissions={['admin', 'gestor']} />} />
          <Route path="/financeiro" element={<PrivateRoute element={<ReceitasDespesas />} permissions={['admin', 'gestor']} />} />
          <Route path="/financeiro/extrato" element={<PrivateRoute element={<ExtratoConta />} permissions={['admin', 'gestor']} />} />
          <Route path="/financeiro/solicitacoes" element={<PrivateRoute element={<Solicitacoes />} permissions={['admin', 'gestor']} />} />
          <Route path="/financeiro/integracao-receitas" element={<PrivateRoute element={<IntegracaoReceitas />} permissions={['admin', 'gestor']} />} />
          <Route path="/financeiro/integracao-despesas" element={<PrivateRoute element={<IntegracaoDespesas />} permissions={['admin', 'gestor']} />} />
          <Route path="/financeiro/relatorios" element={<PrivateRoute element={<RelatoriosFinanceiro />} permissions={['admin', 'gestor']} />} />
          <Route path="/documentos" element={<PrivateRoute element={<Documentos />} permissions={['admin', 'gestor']} />} />
          <Route path="/documentos/modelos" element={<PrivateRoute element={<ModelosDocumentos />} permissions={['admin', 'gestor']} />} />
          <Route path="/extensoes" element={<PrivateRoute element={<Conexoes />} permissions={['admin', 'gestor']} />} />
          <Route path="/extensoes/relatorios" element={<PrivateRoute element={<RelatoriosExtensoes />} permissions={['admin', 'gestor']} />} />
        </Routes>
        <div className="calendar-container">
          <Calendar />
        </div>
      </div>
    </Router>
  );
};

export default App;
